import React from 'react'
import "./Chat.scss"
import ChatHeader from './ChatHeader'
import AddCircleOutlineIcon from '@mui/icons-material/AddCircleOutline';

const Chat = () => {
  return (
    <div className='chat'>
      <ChatHeader />
      <div className='chatMessage'></div>
      <div className='chatInput'>
        <AddCircleOutlineIcon />
      </div>
    </div>
  )
}

export default Chat
